// Idempotent payment processing
public PaymentResult processPayment(
    PaymentRequest req, String idempotencyKey) {

  // Try to insert — fails if key exists
  try {
    db.insert("""
      INSERT INTO payments
        (idempotency_key, amount, status)
      VALUES (?, ?, 'PENDING')
    """, idempotencyKey, req.amount);
  } catch (DuplicateKeyException e) {
    // Already processed — return existing result
    return db.findByIdempotencyKey(idempotencyKey);
  }

  // Distributed lock prevents parallel processing
  try (Lock lock = redis.lock(idempotencyKey, 30s)) {
    PaymentResult result = stripeClient.charge(req);
    db.update(idempotencyKey, result.status);
    return result;
  }
}

