// Redis leader election with renewal
public class LeaderElection {
  private final RedissonClient redis;
  private final String nodeId = UUID.randomUUID().toString();

  public boolean tryBecomeLeader() {
    RBucket<String> leader = redis.getBucket("cluster:leader");
    // Atomic: set only if absent, 30s TTL
    return leader.setIfAbsent(nodeId, Duration.ofSeconds(30));
  }

  @Scheduled(fixedDelay = 10_000) // renew every 10s
  public void renewLeadership() {
    RBucket<String> leader = redis.getBucket("cluster:leader");
    if (nodeId.equals(leader.get())) {
      leader.expire(Duration.ofSeconds(30)); // renew TTL
      performLeaderTasks();
    }
  }
}

// POST /orders with idempotency
@PostMapping("/orders")
public ResponseEntity<Order> createOrder(
    @RequestHeader("Idempotency-Key") String idemKey,
    @RequestBody OrderRequest req) {

  // Check cache
  String cached = redis.get("idem:" + idemKey);
  if (cached != null)
    return ResponseEntity.ok(parse(cached)); // replay

  // Execute
  Order order = orderService.create(req);

  // Cache result (24h TTL)
  redis.set("idem:" + idemKey,
            serialize(order),
            Duration.ofHours(24));

  return ResponseEntity.status(201).body(order);
}

// Lock-based cache population (Java)
public Product getProduct(String id) {
  Product cached = redis.get("product:" + id);
  if (cached != null) return cached;

  // Only one thread fetches from DB
  String lockKey = "lock:product:" + id;
  boolean locked = redis.setIfAbsent(
      lockKey, "1", Duration.ofSeconds(5));

  if (locked) {
    try {
      Product p = db.findById(id);  // fetch once
      // Add jitter: TTL = 5min ± 30s
      int ttl = 300 + ThreadLocalRandom.current()
                                       .nextInt(-30, 30);
      redis.set("product:" + id, p, Duration.ofSeconds(ttl));
      return p;
    } finally {
      redis.delete(lockKey);
    }
  } else {
    // Wait briefly then retry (others got the lock)
    Thread.sleep(50);
    return getProduct(id);
  }
}

