// SDK evaluation (in-process, zero latency)
public boolean isEnabled(String flag, User user) {
  FlagDefinition def = localCache.get(flag);
  if (def == null || !def.enabled) return false;

  // Check targeting rules first
  for (Rule rule : def.rules)
    if (matches(user, rule)) return true;

  // Percentage rollout: deterministic by userId
  int bucket = Math.abs(
    (flag + user.id).hashCode()) % 100;
  return bucket < def.rolloutPct;
}

